# Category: mfa_bypass

from flask import Flask, request, jsonify, session, redirect
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps
import secrets
import time

app = Flask(__name__)
app.config["SECRET_KEY"] = "change-this-secret-key"
app.config["RESET_TOKEN_MAX_AGE_SECONDS"] = 3600
app.config["SESSION_COOKIE_HTTPONLY"] = True
app.config["SESSION_COOKIE_SAMESITE"] = "Lax"

serializer = URLSafeTimedSerializer(app.config["SECRET_KEY"])

users = {
    "alice@example.com": {
        "email": "alice@example.com",
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "mfa_secret": "ALICE-MFA-SECRET",
        "mfa_recovery_version": 0,
        "pending_login": None,
    }
}

sent_emails = []

def send_email(to_email, subject, body):
    sent_emails.append({
        "to": to_email,
        "subject": subject,
        "body": body,
        "sent_at": int(time.time())
    })
    print(f"=== EMAIL TO {to_email} ===")
    print(f"Subject: {subject}")
    print(body)
    print("==========================")

def get_user(email):
    if not email:
        return None
    return users.get(email.lower())

def require_auth(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        email = session.get("user_email")
        if not email:
            return jsonify({"error": "authentication required"}), 401
        user = get_user(email)
        if not user:
            session.clear()
            return jsonify({"error": "authentication required"}), 401
        return f(user, *args, **kwargs)
    return wrapper

def issue_mfa_reset_token(user):
    payload = {
        "email": user["email"],
        "recovery_version": user["mfa_recovery_version"],
        "nonce": secrets.token_urlsafe(16)
    }
    return serializer.dumps(payload, salt="mfa-reset")

def verify_mfa_reset_token(token, max_age):
    data = serializer.loads(token, salt="mfa-reset", max_age=max_age)
    email = data.get("email")
    recovery_version = data.get("recovery_version")
    user = get_user(email)
    if not user:
        raise BadSignature("invalid user")
    if recovery_version != user["mfa_recovery_version"]:
        raise BadSignature("stale token")
    return user

@app.route("/register", methods=["POST"])
def register():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    password = data.get("password") or ""
    if not email or not password:
        return jsonify({"error": "email and password required"}), 400
    if email in users:
        return jsonify({"error": "user already exists"}), 409
    users[email] = {
        "email": email,
        "password_hash": generate_password_hash(password),
        "mfa_enabled": False,
        "mfa_secret": None,
        "mfa_recovery_version": 0,
        "pending_login": None,
    }
    return jsonify({"message": "registered"}), 201

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    password = data.get("password") or ""
    user = get_user(email)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "invalid credentials"}), 401

    if user["mfa_enabled"]:
        challenge_id = secrets.token_urlsafe(16)
        user["pending_login"] = {
            "challenge_id": challenge_id,
            "created_at": int(time.time())
        }
        return jsonify({
            "message": "mfa required",
            "mfa_required": True,
            "challenge_id": challenge_id
        }), 200

    session.clear()
    session["user_email"] = user["email"]
    return jsonify({
        "message": "logged in",
        "mfa_required": False
    }), 200

@app.route("/verify-mfa", methods=["POST"])
def verify_mfa():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    challenge_id = data.get("challenge_id") or ""
    code = data.get("code") or ""
    user = get_user(email)
    if not user:
        return jsonify({"error": "invalid challenge"}), 400

    pending = user.get("pending_login")
    if not pending or pending.get("challenge_id") != challenge_id:
        return jsonify({"error": "invalid challenge"}), 400

    if code != "000000":
        return jsonify({"error": "invalid mfa code"}), 401

    user["pending_login"] = None
    session.clear()
    session["user_email"] = user["email"]
    return jsonify({"message": "logged in"}), 200

@app.route("/logout", methods=["POST"])
def logout():
    session.clear()
    return jsonify({"message": "logged out"}), 200

@app.route("/me", methods=["GET"])
@require_auth
def me(user):
    return jsonify({
        "email": user["email"],
        "mfa_enabled": user["mfa_enabled"]
    }), 200

@app.route("/enable-mfa", methods=["POST"])
@require_auth
def enable_mfa(user):
    if user["mfa_enabled"]:
        return jsonify({"message": "mfa already enabled"}), 200
    user["mfa_enabled"] = True
    user["mfa_secret"] = secrets.token_urlsafe(16)
    user["mfa_recovery_version"] += 1
    return jsonify({
        "message": "mfa enabled",
        "mfa_enabled": True
    }), 200

@app.route("/disable-mfa", methods=["POST"])
@require_auth
def disable_mfa(user):
    data = request.get_json(silent=True) or {}
    password = data.get("password") or ""
    if not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "password confirmation required"}), 401
    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["pending_login"] = None
    user["mfa_recovery_version"] += 1
    return jsonify({
        "message": "mfa disabled",
        "mfa_enabled": False
    }), 200

@app.route("/reset-mfa", methods=["POST"])
def reset_mfa():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()

    if email:
        user = get_user(email)
        if user:
            token = issue_mfa_reset_token(user)
            reset_url = request.host_url.rstrip("/") + "/reset-mfa/confirm?token=" + token
            send_email(
                user["email"],
                "Reset your MFA settings",
                f"Use this link to reset your MFA settings:\n\n{reset_url}\n\n"
                f"This link will disable MFA for your account and allow login with only your password.\n"
                f"If you did not request this, you can ignore this email."
            )

    return jsonify({
        "message": "If the account exists, a reset link has been sent to the registered email."
    }), 200

@app.route("/reset-mfa/confirm", methods=["GET", "POST"])
def confirm_reset_mfa():
    token = request.args.get("token") or request.form.get("token") or ""
    if not token:
        return jsonify({"error": "token required"}), 400

    try:
        user = verify_mfa_reset_token(token, app.config["RESET_TOKEN_MAX_AGE_SECONDS"])
    except SignatureExpired:
        return jsonify({"error": "reset link expired"}), 400
    except BadSignature:
        return jsonify({"error": "invalid reset link"}), 400

    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["pending_login"] = None
    user["mfa_recovery_version"] += 1

    return jsonify({
        "message": "mfa has been reset and disabled; you can now log in with password only",
        "email": user["email"],
        "mfa_enabled": False
    }), 200

